#include <bits/stdc++.h>
using namespace std;
int n,a,b,w[500005];
priority_queue<int> p;
int main(){
    cin>>n>>a>>b;
    for(int i=1;i<=n;i++){
        cin>>w[i];
        p.push(w[i]);
    }
    int day=0;
    while(p.size()){
        int t=p.top();
        p.pop();
        if(t-day*a>0){
            day++;
            if(t-day*a-b>0)
                p.push(t-b);
        }
    }
    cout<<day;
    return 0;
}
